// src/context/SkillsContext.js

import React,
{
 createContext,
 useContext,
 useEffect,
 useState
}
from "react";

import { useAuth }
from "./AuthContext";

import {
 getSkills,
 addSkill,
 updateSkill,
 deleteSkill
}
from "../services/userService";


const SkillsContext =
createContext(null);


export function useSkills(){

 return useContext(
  SkillsContext
 );

}


export function SkillsProvider(
 { children }
){

 const { user } =
 useAuth();

 const [skills,setSkills] =
 useState([]);

 const [loadingData,setLoadingData] =
 useState(true);


 useEffect(()=>{

 async function load(){

  if(!user) return;

  try{

   const data =
   await getSkills(
    user.uid
   );

   setSkills(data);

  }catch(err){

   console.error(err);

  }

  setLoadingData(false);

 }

 load();

 },[user]);



 async function createSkill(skill){

  const id =
  await addSkill(
   user.uid,
   skill
  );

  setSkills(prev=>[

   ...prev,
   { id,...skill }

  ]);

 }



 async function editSkill(id,data){

  await updateSkill(
   user.uid,
   id,
   data
  );

  setSkills(prev=>

   prev.map(s=>

    s.id===id ?

    { ...s,...data }

    :

    s

   )

  );

 }



 async function removeSkill(id){

  await deleteSkill(
   user.uid,
   id
  );

  setSkills(prev=>

   prev.filter(
    s=>s.id!==id
   )

  );

 }



 const value={

  skills,
  loadingData,
  createSkill,
  editSkill,
  removeSkill

 };


 return(

 <SkillsContext.Provider
 value={value}>

 {children}

 </SkillsContext.Provider>

 );

}
